import React, { useState } from 'react';
import { projects } from '../../data';
import './Projects.css';

const allTags = ['All', ...Array.from(new Set(projects.flatMap((p) => p.tags)))];

export default function Projects() {
  const [filter, setFilter] = useState('All');

  const filtered = filter === 'All'
    ? projects
    : projects.filter((p) => p.tags.includes(filter));

  return (
    <section id="projects">
      <div className="container">
        <div className="section-tag">04 // Projects</div>
        <h2 className="section-title">Featured Work</h2>

        <div className="projects-filter">
          {['All', 'AWS', 'Azure', 'Docker', 'CI/CD', 'React.js'].map((tag) => (
            <button
              key={tag}
              className={`filter-btn ${filter === tag ? 'active' : ''}`}
              onClick={() => setFilter(tag)}
            >
              {tag}
            </button>
          ))}
        </div>

        <div className="projects-grid">
          {filtered.map((proj, i) => (
            <div className="project-card nm-card reveal" key={i}>
              <div className="project-card-top">
                <span className="project-emoji">{proj.emoji}</span>
                <div className="project-links">
                  {proj.github && (
                    <a href={proj.github} className="project-link" target="_blank" rel="noreferrer" title="GitHub">
                      <i className="fab fa-github" />
                    </a>
                  )}
                  {proj.live && (
                    <a href={proj.live} className="project-link" target="_blank" rel="noreferrer" title="Live">
                      <i className="fas fa-external-link-alt" />
                    </a>
                  )}
                </div>
              </div>
              <div className="project-title">{proj.title}</div>
              <p className="project-desc">{proj.desc}</p>
              <div className="project-tags">
                {proj.tags.map((t) => (
                  <span className="project-tag" key={t}>{t}</span>
                ))}
              </div>
            </div>
          ))}
        </div>

        {filtered.length === 0 && (
          <div className="no-results">
            <i className="fas fa-search" />
            <p>No projects match this filter.</p>
          </div>
        )}
      </div>
    </section>
  );
}
